const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);

const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

app.use(express.json());

const PORT = process.env.PORT || 3000;
const SESSION_TTL_MS = 1000 * 60 * 60 * 24;
const USERNAME_MIN = 3;
const USERNAME_MAX = 20;
const SCORE_MIN = 0;
const SCORE_MAX = 1000000000;

const sessions = new Map();
const players = new Map();
const leaderboard = new Map();

function now() {
  return Date.now();
}

function createToken() {
  return crypto.randomBytes(32).toString('hex');
}

function sanitizeUsername(value) {
  if (typeof value !== 'string') return null;
  const username = value.trim();
  if (username.length < USERNAME_MIN || username.length > USERNAME_MAX) return null;
  if (!/^[a-zA-Z0-9_]+$/.test(username)) return null;
  return username;
}

function validateScore(value) {
  if (typeof value !== 'number' || !Number.isFinite(value)) return null;
  if (!Number.isInteger(value)) return null;
  if (value < SCORE_MIN || value > SCORE_MAX) return null;
  return value;
}

function createSession(username) {
  const token = createToken();
  const session = {
    token,
    username,
    createdAt: now(),
    expiresAt: now() + SESSION_TTL_MS
  };
  sessions.set(token, session);
  return session;
}

function getSession(token) {
  if (typeof token !== 'string' || !token) return null;
  const session = sessions.get(token);
  if (!session) return null;
  if (session.expiresAt < now()) {
    sessions.delete(token);
    return null;
  }
  session.expiresAt = now() + SESSION_TTL_MS;
  return session;
}

function serializeLeaderboard(limit = 20) {
  return Array.from(leaderboard.entries())
    .map(([username, score]) => ({ username, score }))
    .sort((a, b) => b.score - a.score || a.username.localeCompare(b.username))
    .slice(0, limit);
}

function upsertLeaderboard(username, score) {
  const prev = leaderboard.get(username) ?? 0;
  if (score > prev) {
    leaderboard.set(username, score);
  }
}

setInterval(() => {
  const ts = now();
  for (const [token, session] of sessions.entries()) {
    if (session.expiresAt < ts) {
      sessions.delete(token);
    }
  }
}, 60 * 1000);

