io.use((socket, next) => {
  const token =
    socket.handshake.auth?.token ||
    socket.handshake.headers['x-session-token'] ||
    socket.handshake.query?.token;

  const session = getSession(token);
  if (!session) {
    return next(new Error('Unauthorized'));
  }

  socket.data.session = session;
  next();
});

io.on('connection', (socket) => {
  const { username, token } = socket.data.session;

  players.set(socket.id, {
    socketId: socket.id,
    username,
    token,
    connectedAt: now(),
    lastSeenAt: now(),
    score: leaderboard.get(username) ?? 0
  });

  socket.emit('session', {
    username,
    token,
    score: leaderboard.get(username) ?? 0,
    leaderboard: serializeLeaderboard()
  });

  socket.broadcast.emit('player:joined', {
    username
  });

  socket.on('player:move', (payload = {}) => {
    const player = players.get(socket.id);
    if (!player) return;

    player.lastSeenAt = now();

    const move = {
      x: typeof payload.x === 'number' && Number.isFinite(payload.x) ? payload.x : 0,
      y: typeof payload.y === 'number' && Number.isFinite(payload.y) ? payload.y : 0,
      direction: typeof payload.direction === 'string' ? payload.direction : 'none',
      timestamp: typeof payload.timestamp === 'number' && Number.isFinite(payload.timestamp) ? payload.timestamp : now()
    };

    io.emit('player:moved', {
      username: player.username,
      move
    });
  });

  socket.on('player:score', (payload = {}, ack) => {
    const player = players.get(socket.id);
    if (!player) {
      if (typeof ack === 'function') ack({ ok: false, error: 'Player not found' });
      return;
    }

    player.lastSeenAt = now();

    const score = validateScore(payload.score);
    if (score === null) {
      if (typeof ack === 'function') ack({ ok: false, error: 'Invalid score' });
      return;
    }

    player.score = score;
    upsertLeaderboard(player.username, score);

    const board = serializeLeaderboard();

    io.emit('leaderboard:update', {
      leaderboard: board
    });

    if (typeof ack === 'function') {
      ack({
        ok: true,
        username: player.username,
        score,
        leaderboard: board
      });
    }
  });

  socket.on('player:state', (payload = {}) => {
    const player = players.get(socket.id);
    if (!player) return;

    player.lastSeenAt = now();

    io.emit('player:state', {
      username: player.username,
      state: payload
    });
  });

  socket.on('disconnect', () => {
    const player = players.get(socket.id);
    if (player) {
      players.delete(socket.id);
      socket.broadcast.emit('player:left', {
        username: player.username
      });
    }
  });
});

